import{_ as e,c as o,o as t,a4 as i}from"./chunks/framework.ttppV29E.js";const m=JSON.parse('{"title":"Task Owner","description":"","frontmatter":{},"headers":[],"relativePath":"docs/tasks/owner.md","filePath":"docs/tasks/owner.md","lastUpdated":1777969749000}'),r={name:"docs/tasks/owner.md"},a=i('<h1 id="task-owner" tabindex="-1">Task Owner <a class="header-anchor" href="#task-owner" aria-label="Permalink to &quot;Task Owner&quot;">​</a></h1><p>The <code>owner</code> and <code>owner type</code> fields represents the user or entity who &quot;owns&quot; a task at a given point in the workflow. AireFlow itself does not rely on either property for anything, but other systems such as AireFrame can use it.</p><p><code>owner</code> and <code>owner type</code> are optional properties.</p><h2 id="how-it-s-set" tabindex="-1">How it’s set <a class="header-anchor" href="#how-it-s-set" aria-label="Permalink to &quot;How it’s set&quot;">​</a></h2><p>The <code>owner</code> can be assigned or updated through several mechanisms:</p><ol><li><p><strong>Workflow definition</strong></p><ul><li>An <code>owner</code> can be configured for each task in the workflow builder.</li><li>Supports dynamic expressions (e.g. XPath or Liquid), similar to other configurable fields like <code>name</code> or <code>assignee</code>.</li></ul></li><li><p><strong>Event propagation</strong></p><ul><li>The <code>owner</code> is automatically included in any events emitted by a task.</li><li>When a task is triggered by an event from another task: <ul><li>The <code>owner</code> is set from the event payload <strong>by default</strong></li><li>If the task definition specifies an XPath/Liquid expression for <code>owner</code>, that expression <strong>takes precedence</strong> over the owner from the event</li></ul></li></ul></li><li><p><strong>API updates</strong></p><ul><li>The <code>owner</code> can be modified at runtime via the PATCH API or via a <a href="./../workflows/mutations.html">Mutation</a>.</li></ul></li><li><p><strong>From AireFrame</strong></p><ul><li>When a task is updated via AireFrame, the <code>owner</code> and <code>owner type</code> will automatically be set to reflect the user who made the update.</li></ul></li></ol><h2 id="owner-type" tabindex="-1">Owner Type <a class="header-anchor" href="#owner-type" aria-label="Permalink to &quot;Owner Type&quot;">​</a></h2><p>When using the owner to refer to an AireFrame user, the <code>owner type</code> field should be used to keep track of the type of AireFrame user so the user can be rendered correctly. AireFrame supports the following owner types:</p><ul><li><strong>User</strong> - Looks up the ID against AireAuth and shows the user’s display name</li><li><strong>Subject</strong> - Looks up the ID against AireFrame subjects and shows the primary field value</li><li><strong>Subject Proxy</strong> - Looks up the ID against AireAuth and shows the user’s display name</li><li><strong>External</strong> - Shows as <code>[Id] (External)</code></li><li><strong>Client Credentials</strong> - Shows as <code>[Id] (System)</code></li><li><strong>System</strong> - Shows as <code>[Id]</code></li><li><strong>Unknown</strong> - Shows as <code>[Id]</code></li></ul><h2 id="behavior-and-considerations" tabindex="-1">Behavior and considerations <a class="header-anchor" href="#behavior-and-considerations" aria-label="Permalink to &quot;Behavior and considerations&quot;">​</a></h2><ul><li>The <code>owner</code> and <code>owner type</code> fields are <strong>optional and mutable</strong>.</li><li>Ownership can be dynamically resolved at runtime using expressions.</li><li>Propagation through events ensures continuity of ownership across workflow steps.</li><li>Explicit configuration (XPath/Liquid) overrides inherited values from task events.</li><li>API updates can override previously set values at any point in the task lifecycle.</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><ul><li>Task A is defined with <code>owner = User1</code></li><li>Task A emits an event with <code>owner = User1</code></li><li>Task B is triggered by the event: <ul><li>If no expression is defined → <code>owner = User1</code> (inherited)</li><li>If <code>owner</code> is defined as an expression → evaluated result is used instead</li></ul></li><li>Task B is later updated by User2 in AireFrame → <code>owner = User2</code></li></ul>',13),s=[a];function n(l,d,c,h,u,p){return t(),o("div",null,s)}const f=e(r,[["render",n]]);export{m as __pageData,f as default};
